  // Replace all read<U...>() calls with a helper that reads from stdin tokens
  const prefix = "read<U";
  const suffix = ">()";
  let result = "";
  let i = 0;
  while (i < tuffSourceCode.length) {
    if (tuffSourceCode.slice(i, i + prefix.length) === prefix) {
      // Check for valid read pattern: read<U followed by digits and >()
      const restStart = i + prefix.length;
      let j = restStart;
      while (j < tuffSourceCode.length) {
        const ch = tuffSourceCode[j];
        if (!ch || ch < "0" || ch > "9") break;
        j++;
      }

      if (j < tuffSourceCode.length - suffix.length + 1) {
        const afterDigits = tuffSourceCode.slice(j, j + suffix.length);
        if (afterDigits === suffix) {
          result += "read()";
          i = j + suffix.length;
          continue;
        }
      }
    }

    // Skip type annotations like ": U8", ": U16" etc.
    if (tuffSourceCode[i] === ":" && tuffSourceCode[i + 1] === " ") {
      i += 2; // skip ": "
      while (i < tuffSourceCode.length) {
        const ch = tuffSourceCode[i];
        if (!ch || !isAlphaNumeric(ch)) break;
        i++;
      }
      continue;
    }

    result += tuffSourceCode[i];
    i++;
  }

  // Split by semicolons, last part is the return expression
  const parts = result.split(";");
  let body = "";
  for (let p = 0; p < parts.length - 1; p++) {
    const stmt = trim(parts[p]);
    if (stmt !== "") {
      body += stmt + ";\n";
    }
  }
  const lastExpr = trim(parts[parts.length - 1]);

  return (
    'const inputs = stdIn.split(" ").map(Number);\nlet idx = 0;\nfunction read() { return inputs[idx++]; }\n' +
    body +
    "return " +
    lastExpr +
    ";"
  );
}

function isAlphaNumeric(ch: string): boolean {
  if (ch >= "a" && ch <= "z") return true;
  if (ch >= "A" && ch <= "Z") return true;
  if (ch >= "0" && ch <= "9") return true;
  return false;
}

function trim(s: string): string {
  let start = 0;
  while (start < s.length && (s[start] === " " || s[start] === "\t")) start++;
  let end = s.length;
  while (end > start && (s[end - 1] === " " || s[end - 1] === "\t")) end--;
  return s.slice(start, end);
}
